"""Glossary for tooltips — every term explained simply with a numeric example."""

GLOSSARY: dict[str, str] = {
    "Market Cap": "Рыночная капитализация — сколько стоит вся компания на бирже. Считается как цена акции × число акций. $1 трлн — гиганты типа Apple, $1 млрд — средняя.",
    "Sector": "Сектор экономики, к которому относится бизнес: Technology, Healthcare, Financials и т.д. Помогает сравнивать с похожими компаниями.",
    "Revenue": "Выручка — все деньги, которые компания получила от продаж. Это «верхняя строка» отчёта. До любых расходов.",
    "COGS": "Себестоимость — прямые затраты на производство того, что продают (материалы, зарплаты на заводе). Чем меньше, тем лучше.",
    "Gross Profit": "Валовая прибыль = Выручка − Себестоимость. Деньги, оставшиеся после прямых затрат, до офисов и маркетинга.",
    "GM": "Валовая маржа = Gross Profit / Revenue. Сколько центов с каждого $1 продаж остаётся после себестоимости. 70% — Apple-уровень (бренд/IP), 10% — типичный ритейл.",
    "OpEx": "Операционные расходы — всё, что не себестоимость: зарплаты офиса, маркетинг, R&D, аренда. Считаются после Gross Profit.",
    "Operating Income": "Операционная прибыль = Gross Profit − OpEx. Сколько компания зарабатывает на основном бизнесе, до налогов и процентов по долгу.",
    "OM": "Операционная маржа = Operating Income / Revenue. >20% — отлично, ~10% — средне, отрицательная — компания убыточная.",
    "Net Income": "Чистая прибыль — то, что остаётся после всего: налогов, процентов, разовых списаний. «Нижняя строка» отчёта.",
    "FCF": "Свободный денежный поток = операционный денежный поток − инвестиции в основные средства. «Живые» деньги, которые остаются после поддержки бизнеса. Важнее чистой прибыли, потому что её сложнее «нарисовать».",
    "ROIC": "Доходность на вложенный капитал = NOPAT / (Equity + Debt − Cash). Сколько центов компания зарабатывает на каждый $1 капитала. >15% — отличный бизнес, ~10% — средний, <5% — слабый.",
    "Revenue CAGR": "Среднегодовой темп роста выручки. CAGR 10% значит «выручка росла на 10% в год каждый год в среднем».",
    "P/E": "Цена / Прибыль. Сколько лет компания будет окупаться при текущей чистой прибыли. P/E=20 — окупится за 20 лет. У SP500 средний ~18-22. P/E=50 — дорого, P/E=10 — дёшево (или есть проблема).",
    "P/S": "Цена / Выручка. Сколько $ платим за $1 годовых продаж. Для растущих SaaS — 10-20 норма, для ритейла — 0.5-1.",
    "EV/EBITDA": "Enterprise Value / EBITDA. Учитывает долг и кэш, поэтому честнее P/E. <10 — обычно дёшево, >20 — дорого.",
    "P/FCF": "Цена / Свободный денежный поток. Аналог P/E, но по «живым» деньгам. <20 — разумно, >40 — дорого.",
    "Moat": "«Ров» — устойчивое конкурентное преимущество, которое не даёт конкурентам отнять прибыль. Бывает 5 типов: бренд/патенты, switching costs, network effects, преимущество в издержках, эффективный масштаб.",
    "Intangibles": "Нематериальные активы — бренды, патенты, лицензии. Главный ров Coca-Cola и Pfizer.",
    "Switching Costs": "Издержки переключения. Когда уйти к конкуренту дорого/сложно (переучивать персонал, переносить данные). Главный ров Microsoft и Oracle.",
    "Network Effects": "Сетевой эффект. Чем больше пользователей, тем ценнее продукт. Главный ров Visa и Facebook.",
    "Cost Advantage": "Структурное преимущество в себестоимости — масштаб, эксклюзивный доступ к сырью, географическое преимущество. Walmart, Costco.",
    "Efficient Scale": "Эффективный масштаб — узкий рынок вмещает только пару игроков. Железные дороги, рейтинговые агентства.",
    "10-K": "Годовой отчёт компании в SEC. Главный документ о бизнесе, рисках, финансах. 100+ страниц.",
    "10-Q": "Квартальный отчёт. Короче 10-K, без полного описания бизнеса, но с свежими цифрами.",
    "Target Price": "Целевая цена аналитиков — сколько по мнению инвестбанков должна стоить акция через 12 месяцев.",
}


def help_for(term: str) -> str:
    return GLOSSARY.get(term, "")
